const API_BASE_URL = 'http://localhost:5000';

function Community({ user }) {
  // --- New State for Mood Wall ---
  const [communityPosts, setCommunityPosts] = useState([]);
  const [selectedMood, setSelectedMood] = useState('neutral');
  const [newPostText, setNewPostText] = useState('');
  const [isCreatingPost, setIsCreatingPost] = useState(false);

  // --- Restored State for Groups & Events ---
  const [groups, setGroups] = useState(initialGroups);
  const [activeTab, setActiveTab] = useState('feed'); // Start on feed
  const [selectedGroup, setSelectedGroup] = useState(null);
  const [newMessage, setNewMessage] = useState('');
  const [replyingTo, setReplyingTo] = useState(null);
  const [editingMessage, setEditingMessage] = useState(null);
  const [replyText, setReplyText] = useState('');
  const [eventReminders, setEventReminders] = useState({});
  const messagesEndRef = useRef(null);

  const fetchPosts = async () => {
    try {
      const response = await fetch(`${API_BASE_URL}/api/community/posts`);
      const data = await response.json();
      if (data.status === 'success') {
        setCommunityPosts(data.posts);
      }
    } catch (err) {
      console.error("Failed to fetch community posts", err);
    }
  };

  useEffect(() => {
    fetchPosts();
    // Simulate real-time WebSockets by auto-polling the community feed every 4 seconds
    const interval = setInterval(() => {
      fetchPosts();
    }, 4000);
    return () => clearInterval(interval);
  }, []);

  // Scroll to bottom of chat
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [selectedGroup?.messages, replyingTo]);

  const handleAddPost = async () => {
    if (newPostText.trim() === "") return;

    try {
      const response = await fetch(`${API_BASE_URL}/api/community/posts`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          mood_tag: selectedMood,
          content: newPostText
        })
      });
      if (response.ok) {
        setNewPostText('');
        setIsCreatingPost(false);
        fetchPosts();
      }
    } catch (err) {
      console.error("Failed to share mood", err);
    }
  };

  const handleReactToPost = async (postId, reactionType) => {
    try {
      const response = await fetch(`${API_BASE_URL}/api/community/react`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          post_id: postId,
          reaction_type: reactionType
        })
      });
      if (response.ok) {
        fetchPosts();
      }
    } catch (err) {
      console.error("Failed to react", err);
    }
  };

  // --- Restored Helper Functions ---
  const handleJoinGroup = (groupId) => {
    setGroups(prevGroups =>
      prevGroups.map(group =>
        group.id === groupId ? {
          ...group,
          isMember: !group.isMember,
          members: group.isMember ? group.members - 1 : group.members + 1
        } : group
      )
    );
  };

  const handleSendMessage = () => {
    if (newMessage.trim() !== "" && selectedGroup) {
      const updatedGroups = groups.map(group => {
        if (group.id === selectedGroup.id) {
          const newMessageObj = {
            id: group.messages.length + 1,
            user: user?.username || "You",
            text: newMessage,
            time: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
            reactions: {},
            replies: []
          };
          return { ...group, messages: [...group.messages, newMessageObj] };
        }
        return group;
      });
      setGroups(updatedGroups);
      setSelectedGroup(updatedGroups.find(g => g.id === selectedGroup.id));
      setNewMessage('');
    }
  };

  const handleReactToMessage = (groupId, messageId, reaction) => {
    const updatedGroups = groups.map(group => {
      if (group.id === groupId) {
        const updatedMessages = group.messages.map(message => {
          if (message.id === messageId) {
            const currentReactions = { ...message.reactions };
            currentReactions[reaction] = (currentReactions[reaction] || 0) + 1;
            return { ...message, reactions: currentReactions };
          }
          return message;
        });
        return { ...group, messages: updatedMessages };
      }
      return group;
    });
    setGroups(updatedGroups);
    if (selectedGroup && selectedGroup.id === groupId) {
      setSelectedGroup(updatedGroups.find(g => g.id === groupId));
    }
  };

  const handleReplyToMessage = (groupId, messageId) => {
    if (replyText.trim() !== "") {
      const updatedGroups = groups.map(group => {
        if (group.id === groupId) {
          const updatedMessages = group.messages.map(message => {
            if (message.id === messageId) {
              const newReply = {
                id: message.replies.length + 1,
                user: user?.username || "You",
                text: replyText,
                time: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
              };
              return { ...message, replies: [...message.replies, newReply] };
            }
            return message;
          });
          return { ...group, messages: updatedMessages };
        }
        return group;
      });
      setGroups(updatedGroups);
      if (selectedGroup && selectedGroup.id === groupId) {
        setSelectedGroup(updatedGroups.find(g => g.id === groupId));
      }
      setReplyText('');
      setReplyingTo(null);
    }
  };

  const handleEditMessage = (groupId, messageId, newText) => {
    const updatedGroups = groups.map(group => {
      if (group.id === groupId) {
        const updatedMessages = group.messages.map(message => {
          if (message.id === messageId && message.user === (user?.username || "You")) {
            return { ...message, text: newText, edited: true };
          }
          return message;
        });
        return { ...group, messages: updatedMessages };
      }
      return group;
    });
    setGroups(updatedGroups);
    if (selectedGroup && selectedGroup.id === groupId) {
      setSelectedGroup(updatedGroups.find(g => g.id === groupId));
    }
    setEditingMessage(null);
  };

  const handleDeleteMessage = (groupId, messageId) => {
    const updatedGroups = groups.map(group => {
      if (group.id === groupId) {
        const updatedMessages = group.messages.filter(message =>
          !(message.id === messageId && message.user === (user?.username || "You"))
        );
        return { ...group, messages: updatedMessages };
      }
      return group;
    });
    setGroups(updatedGroups);
    if (selectedGroup && selectedGroup.id === groupId) {
      setSelectedGroup(updatedGroups.find(g => g.id === groupId));
    }
  };

  const handleJoinEvent = (eventId) => {
    alert(`You've joined the event! We'll send you a reminder before it starts.`);
  };

  const handleSetReminder = (eventId) => {
    setEventReminders(prev => ({ ...prev, [eventId]: true }));
    alert(`Reminder set for this event!`);
  };

  const renderEngagementIndicator = (level) => (
    <div className="engagement-indicator">
      <div className="engagement-bar">
        <div className="engagement-fill" style={{ width: `${level}%` }}></div>
      </div>
      <span className="engagement-value">{level}%</span>
    </div>
  );

  const renderActivityLevel = (level) => {
    const levels = {
      "very high": { color: "#10B981", label: "Very Active" },
      "high": { color: "#84CC16", label: "Active" },
      "medium": { color: "#F59E0B", label: "Moderate" },
      "low": { color: "#EF4444", label: "Low" }
    };
    return (
      <span className="activity-level" style={{ color: levels[level]?.color }}>
        ● {levels[level]?.label}
      </span>
    );
  };

  const supportReactions = [
    { type: 'strong', label: '💛 Stay strong' },
    { type: 'alone', label: '🤝 You’re not alone' },
    { type: 'step', label: '🌱 One step at a time' }
  ];

  return (
    <div className="community-hub">
      <div className="community-header">
        <h2>
          <span className="main-title">Community Mood Wall</span>
        </h2>
        <div className="community-controls">
          <div className="view-toggles">
            <button className={`view-toggle ${activeTab === 'feed' ? 'active' : ''}`}
              onClick={() => setActiveTab('feed')}>
              🌍 Public Wall
            </button>
            <button className={`view-toggle ${activeTab === 'groups' ? 'active' : ''}`}
              onClick={() => setActiveTab('groups')}>
              👥 Groups
            </button>
          </div>
        </div>
      </div>

      <div className="community-layout">
        <div className="main-content">
          {activeTab === 'feed' && (
            <div className="mood-wall-section">
              <div className="section-header">
                <h3>Anonymous Mood Wall</h3>
                <p>Sharing your feelings helps others know they're not alone. Completely anonymous.</p>
              </div>

              <div className="create-post-card">
                <div className="post-input">
                  <textarea
                    placeholder="How are you really feeling? Sharing is the first step..."
                    value={newPostText}
                    onChange={(e) => setNewPostText(e.target.value)}
                    onFocus={() => setIsCreatingPost(true)}
                  ></textarea>
                  {isCreatingPost && (
                    <div className="post-options">
                      <div className="mood-selector">
                        <span>Select your mood:</span>
                        <div className="mood-options">
                          {["peaceful", "happy", "neutral", "anxious", "sad", "stressed"].map(m => (
                            <button
                              key={m}
                              className={`mood-option-tag ${selectedMood === m ? 'active' : ''}`}
                              onClick={() => setSelectedMood(m)}
                            >
                              {m}
                            </button>
                          ))}
                        </div>
                      </div>
                      <div className="post-actions">
                        <button className="cancel-btn" onClick={() => {
                          setIsCreatingPost(false);
                          setNewPostText('');
                        }}>Cancel</button>
                        <button className="share-btn" onClick={handleAddPost}>Share Anonymously</button>
                      </div>
                    </div>
                  )}
                </div>
              </div>

              <div className="post-list">
                {communityPosts.map(post => (
                  <div key={post.id} className="post-card anonymous-post">
                    <div className="post-header">
                      <div className="post-mood">
                        <span className={`mood-indicator ${post.mood_tag}`}></span>
                        Feeling {post.mood_tag}
                      </div>
                    </div>
                    <p className="post-content">"{post.content}"</p>
                    <div className="support-reactions">
                      {supportReactions.map(btn => (
                        <button
                          key={btn.type}
                          className="support-btn"
                          onClick={() => handleReactToPost(post.id, btn.type)}
                        >
                          {btn.label} <span className="react-count">{post.reactions?.[btn.type] || 0}</span>
                        </button>
                      ))}
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}

          {activeTab === 'groups' && !selectedGroup && (
            <div className="groups-grid">
              <h3>Support Groups</h3>
              <div className="groups-container">
                {groups.map(group => (
                  <div key={group.id} className={`group-card ${group.isMember ? 'joined' : ''}`}>
                    <div className="group-header">
                      <h4>{group.name}</h4>
                      {renderEngagementIndicator(group.engagementLevel)}
                    </div>
                    <p className="group-description">{group.description}</p>
                    <div className="group-meta">
                      <div className="group-stats">
                        <span className="members-count">👥 {group.members.toLocaleString()} members</span>
                        {renderActivityLevel(group.activity)}
                      </div>
                      <div className="group-tags">
                        {group.tags.map(tag => (
                          <span key={tag} className="tag">#{tag}</span>
                        ))}
                      </div>
                    </div>
                    <div className="group-footer">
                      <button
                        className={`join-btn ${group.isMember ? 'joined' : ''}`}
                        onClick={() => handleJoinGroup(group.id)}
                      >
                        {group.isMember ? 'Joined' : 'Join Group'}
                      </button>
                      <button
                        className="explore-btn"
                        onClick={() => setSelectedGroup(group)}
                      >
                        {group.isMember ? 'Enter Chat' : 'View Group'}
                      </button>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}

          {activeTab === 'groups' && selectedGroup && (
            <div className="group-chat-container">
              <div className="chat-header">
                <button className="back-button" onClick={() => setSelectedGroup(null)}>
                  ← Back
                </button>
                <h3>{selectedGroup.name}</h3>
                <div className="member-count">
                  {selectedGroup.members} members
                </div>
              </div>

              <div className="chat-messages">
                {selectedGroup.messages.map(message => (
                  <div key={message.id} className="message-container">
                    <div
                      className={`message ${message.user === (user?.username || "You") ? 'own-message' : ''}`}
                    >
                      <div className="message-header">
                        <span className="message-user">{message.user}</span>
                        <span className="message-time">{message.time}</span>
                        {message.edited && <span className="edited-indicator">(edited)</span>}
                        {message.user === (user?.username || "You") && (
                          <div className="message-actions">
                            <button
                              className="edit-btn"
                              onClick={() => setEditingMessage({ id: message.id, text: message.text })}
                            >
                              Edit
                            </button>
                            <button
                              className="delete-btn"
                              onClick={() => handleDeleteMessage(selectedGroup.id, message.id)}
                            >
                              Delete
                            </button>
                          </div>
                        )}
                      </div>

                      {editingMessage && editingMessage.id === message.id ? (
                        <div className="edit-message-container">
                          <input
                            type="text"
                            value={editingMessage.text}
                            onChange={(e) => setEditingMessage({ ...editingMessage, text: e.target.value })}
                            className="edit-message-input"
                          />
                          <div className="edit-actions">
                            <button
                              className="save-edit-btn"
                              onClick={() => handleEditMessage(selectedGroup.id, message.id, editingMessage.text)}
                            >
                              Save
                            </button>
                            <button
                              className="cancel-edit-btn"
                              onClick={() => setEditingMessage(null)}
                            >
                              Cancel
                            </button>
                          </div>
                        </div>
                      ) : (
                        <div className="message-content">{message.text}</div>
                      )}

                      <div className="message-reactions">
                        {Object.entries(message.reactions).map(([reaction, count]) => (
                          <span key={reaction} className="reaction">
                            {reaction === 'like' && '👍'}
                            {reaction === 'heart' && '❤️'}
                            {reaction === 'support' && '🤗'}
                            {reaction === 'thanks' && '🙏'}
                            {count}
                          </span>
                        ))}
                        <button
                          className="add-reaction-btn"
                          onClick={() => handleReactToMessage(selectedGroup.id, message.id, 'like')}
                        >
                          +
                        </button>
                      </div>

                      <div className="message-actions-bottom">
                        <button
                          className="react-btn"
                          onClick={() => handleReactToMessage(selectedGroup.id, message.id, 'like')}
                        >
                          👍 Like
                        </button>
                        <button
                          className="reply-btn"
                          onClick={() => setReplyingTo(replyingTo === message.id ? null : message.id)}
                        >
                          💬 Reply
                        </button>
                      </div>
                    </div>

                    {/* Replies */}
                    {message.replies && message.replies.length > 0 && (
                      <div className="replies-container">
                        {message.replies.map(reply => (
                          <div key={reply.id} className="reply">
                            <div className="reply-header">
                              <span className="reply-user">{reply.user}</span>
                              <span className="reply-time">{reply.time}</span>
                            </div>
                            <div className="reply-content">{reply.text}</div>
                          </div>
                        ))}
                      </div>
                    )}

                    {/* Reply input */}
                    {replyingTo === message.id && (
                      <div className="reply-input-container">
                        <input
                          type="text"
                          placeholder="Type your reply..."
                          value={replyText}
                          onChange={(e) => setReplyText(e.target.value)}
                          className="reply-input"
                        />
                        <div className="reply-actions">
                          <button
                            className="send-reply-btn"
                            onClick={() => handleReplyToMessage(selectedGroup.id, message.id)}
                          >
                            Send
                          </button>
                          <button
                            className="cancel-reply-btn"
                            onClick={() => {
                              setReplyingTo(null);
                              setReplyText('');
                            }}
                          >
                            Cancel
                          </button>
                        </div>
                      </div>
                    )}
                  </div>
                ))}
                <div ref={messagesEndRef} />
              </div>

              <div className="chat-input-container">
                <input
                  type="text"
                  placeholder="Type your message here..."
                  value={newMessage}
                  onChange={(e) => setNewMessage(e.target.value)}
                  onKeyPress={(e) => e.key === 'Enter' && handleSendMessage()}
                  className="chat-input"
                />
                <button
                  className="send-button"
                  onClick={handleSendMessage}
                  disabled={!newMessage.trim()}
                >
                  Send
                </button>
              </div>
            </div>
          )}

          {activeTab === 'events' && (
            <div className="events-section">
              <h3>Live Events & Workshops</h3>
              <div className="events-container">
                {initialLiveEvents.map(event => (
                  <div key={event.id} className="event-card">
                    <div className="event-header">
                      <h4>{event.title}</h4>
                      <div className="event-status live">LIVE</div>
                    </div>
                    <div className="event-details">
                      <div className="event-host">
                        <span className="label">Host:</span>
                        <span className="value">{event.host}</span>
                      </div>
                      <div className="event-participants">
                        <span className="label">Participants:</span>
                        <span className="value">{event.participants.toLocaleString()}</span>
                      </div>
                      <div className="event-time">
                        <span className="label">Starts in:</span>
                        <span className="value">{event.startTime}</span>
                      </div>
                      <div className="event-energy">
                        <span className="label">Vibe:</span>
                        <span className="value">{event.energyLevel}</span>
                      </div>
                      <div className="event-description">
                        <p>{event.description}</p>
                      </div>
                    </div>
                    <div className="event-actions">
                      <button
                        className="join-event-btn"
                        onClick={() => handleJoinEvent(event.id)}
                      >
                        Join Event
                      </button>
                      <button
                        className={`remind-btn ${eventReminders[event.id] ? 'reminder-set' : ''}`}
                        onClick={() => handleSetReminder(event.id)}
                      >
                        {eventReminders[event.id] ? 'Reminder Set' : 'Set Reminder'}
                      </button>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

export default Community;
